sealed class ConnectionPublicState {
    
    data class Disconnected(
        val `reason`: kotlin.String?, 
        val `issueHint`: uniffi.isekai_terminal_core.ConnectionIssueHint?) : ConnectionPublicState()
        
    {
        

        companion object
    }
    
    object Connecting : ConnectionPublicState()
    
    
    data class Connected(
        val `host`: kotlin.String) : ConnectionPublicState()
        
    {
        

        companion object
    }
    
    data class Error(
        val `message`: kotlin.String) : ConnectionPublicState()
        
    {
        

        companion object
    }
    
    /**
     * ϊ╕Αί║ο`Connected`ήΒτήΒςήΒμήΒθήΓ╗ήΔΔήΓ╖ήΔπήΔ│ήΒΝϊ║ΙόεθήΒδήΒγίΙΘόΨφήΒΧήΓΝήΒθώγδήΑΒorchestratorήΒΝ
     * ϋΘςίΜΧύγΕήΒτίΗΞόΟξύ╢γήΓΤϋσοήΒ┐ήΒοήΒΕήΓΜώΨΥήΒχύΛ╢όΖΜ(`orchestrator.rs`ήΒχreconnectήΔτήΔ╝ήΔΩίΠΓύΖπ)ήΑΓ
     * `elapsed_secs`/`timeout_secs`ήΒψUIήΒΝήΔσήΓνήΔΨήΒςήΓτήΓοήΔ│ήΔΙήΔΑήΓοήΔ│ήΓΤόΠΠύΦ╗ήΒβήΓΜήΒθήΓΒήΒχ
     * SSOTίΑν(KotlinίΒ┤ήΒπήΓ┐ήΓνήΔηήΔ╝ήΓΤόΝΒήΒθήΒςήΒΕ)ήΑΓ
     */
    data class Reconnecting(
        val `elapsedSecs`: kotlin.UInt, 
        val `timeoutSecs`: kotlin.UInt, 
        val `reason`: kotlin.String?) : ConnectionPublicState()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeConnectionPublicState : FfiConverterRustBuffer<ConnectionPublicState>{
    override fun read(buf: ByteBuffer): ConnectionPublicState {
        return when(buf.getInt()) {
            1 -> ConnectionPublicState.Disconnected(
                FfiConverterOptionalString.read(buf),
                FfiConverterOptionalTypeConnectionIssueHint.read(buf),
                )
            2 -> ConnectionPublicState.Connecting
            3 -> ConnectionPublicState.Connected(
                FfiConverterString.read(buf),
                )
            4 -> ConnectionPublicState.Error(
                FfiConverterString.read(buf),
                )
            5 -> ConnectionPublicState.Reconnecting(
                FfiConverterUInt.read(buf),
                FfiConverterUInt.read(buf),
                FfiConverterOptionalString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ConnectionPublicState) = when(value) {
        is ConnectionPublicState.Disconnected -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
